import{_ as o,o as a,c as t,a3 as i}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"Leads — Production Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Leads — Production Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/deployment/leads"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Leads — Production Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/deployment/leads"}]]},"headers":[],"relativePath":"deployment/leads.md","filePath":"deployment/leads.md","lastUpdated":1784641661000}'),s={name:"deployment/leads.md"};function d(l,e,n,r,c,p){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="leads-—-production-guide" tabindex="-1">Leads — Production Guide <a class="header-anchor" href="#leads-—-production-guide" aria-label="Permalink to &quot;Leads — Production Guide&quot;">​</a></h1><h2 id="licensing" tabindex="-1">Licensing <a class="header-anchor" href="#licensing" aria-label="Permalink to &quot;Licensing&quot;">​</a></h2><ul><li>Catalog slug: <code>leads</code></li><li>Default-included, non-billable for new workspaces</li><li>Deactivate via Central module subscription tools to revoke access without dropping data</li></ul><h2 id="bootstrap" tabindex="-1">Bootstrap <a class="header-anchor" href="#bootstrap" aria-label="Permalink to &quot;Bootstrap&quot;">​</a></h2><p>On workspace provision:</p><ol><li>Default modules installed (includes Leads)</li><li><code>LeadService::ensureDefaultStages()</code> / <code>LeadStageSeeder</code> seeds New → … → Won / Lost</li></ol><p>Existing workspaces without stages get stages lazily on first Leads API call.</p><h2 id="permissions-rollout" tabindex="-1">Permissions rollout <a class="header-anchor" href="#permissions-rollout" aria-label="Permalink to &quot;Permissions rollout&quot;">​</a></h2><p>New Leads permissions for <strong>existing</strong> workspaces must ship as an additive <strong>data migration</strong> using <code>TenantPermissionSynchronizer::grantMissingDefaultRolePermissions([...])</code> (same pattern as Communication Templates). Do <strong>not</strong> re-seed roles or rely on login/dashboard to repair RBAC.</p><p>Status migration maps legacy <code>open</code> → <code>active</code> and <code>won</code>/<code>lost</code> → <code>closed</code>. Column rename: <code>estimated_value</code> → <code>lead_value</code>.</p><h2 id="queue-workers" tabindex="-1">Queue workers <a class="header-anchor" href="#queue-workers" aria-label="Permalink to &quot;Queue workers&quot;">​</a></h2><p>Lead imports always run on the dedicated <code>imports</code> queue:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> queue:work</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --queue=imports,emails,default</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --sleep=1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tries=3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --max-time=3600</span></span></code></pre></div><p>Ensure at least one worker listens to <code>imports</code>. Uploads use the configured <code>filesystems.uploads</code> disk (<code>public</code> locally / <code>s3</code> in production) under <code>imports/{tenant_uuid}/</code>.</p><h2 id="monitoring" tabindex="-1">Monitoring <a class="header-anchor" href="#monitoring" aria-label="Permalink to &quot;Monitoring&quot;">​</a></h2><ul><li>Platform audit events: <code>lead_created</code>, <code>lead_updated</code>, <code>lead_deleted</code>, <code>lead_assigned</code>, <code>lead_stage_changed</code>, <code>lead_note_added</code>, <code>lead_follow_up_*</code>, <code>lead_import_completed</code>, <code>lead_import_failed</code>, convert-related activity</li><li>Mail + database notifications: assignment, follow-up created, follow-up due/overdue (<code>crm:send-due-notifications</code> every 5 minutes)</li><li>Tenant mail settings with Central SMTP fallback</li></ul><h2 id="scheduled-jobs" tabindex="-1">Scheduled jobs <a class="header-anchor" href="#scheduled-jobs" aria-label="Permalink to &quot;Scheduled jobs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Cadence</th><th>Purpose</th></tr></thead><tbody><tr><td><code>crm:send-due-notifications</code></td><td>Every 5 minutes (<code>onOneServer</code>)</td><td>Idempotent due/overdue follow-up (and task) notifications</td></tr></tbody></table><p>Ensure the Laravel scheduler is running in production.</p><h2 id="deploy-checklist" tabindex="-1">Deploy checklist <a class="header-anchor" href="#deploy-checklist" aria-label="Permalink to &quot;Deploy checklist&quot;">​</a></h2><ol><li>Migrate lead tables + Sprint 2 enhance migration + <code>lead_assignment_histories</code> + <code>lead_imports</code></li><li>Deploy frontend (Kanban/table, KPIs, export, import wizard/history, convert stub, notifications)</li><li>Confirm <code>module:leads</code> + expanded permissions (including <code>leads.import</code>)</li><li>Confirm queue worker includes <code>imports</code></li><li>Smoke: register/login → Leads board → create → DnD stage (save) → export → import template → small CSV import → history download → convert stub</li></ol>',21)])])}const m=o(s,[["render",d]]);export{h as __pageData,m as default};
